Patch Set 1:

> Patch Set 1: Verified-1
> 
> fails build on master/master-next now with 
> 
> wirecheck.c:2913:13: error: 'check_nodemap_range2_rec' defined but not used [-Werror=unused-function]
>  static void check_nodemap_range2_rec(void)

The issue should have been fixed in https://review.whamcloud.com/53135 "LU-13307 nodemap: have nodemap_add_member support large NIDs".
This patch adds "check_nodemap_range2_rec()" function in wirecheck.c but never uses it to generate the wiretest entries:

diff --git a/lustre/utils/wirecheck.c b/lustre/utils/wirecheck.c
index 22cb0c2..2fde5cf 100644
--- a/lustre/utils/wirecheck.c
+++ b/lustre/utils/wirecheck.c
@@ -2909,6 +2909,18 @@ static void check_nodemap_range_rec(void)
        CHECK_MEMBER(nodemap_range_rec, nrr_padding2);
 }

+static void check_nodemap_range2_rec(void)
+{
+       BLANK_LINE();
+       CHECK_STRUCT(nodemap_range2_rec);
+       CHECK_MEMBER(nodemap_range2_rec, nrr_nid_prefix);
+       CHECK_MEMBER(nodemap_range2_rec, nrr_padding1);
+       CHECK_MEMBER(nodemap_range2_rec, nrr_padding2);
+       CHECK_MEMBER(nodemap_range2_rec, nrr_padding3);
+       CHECK_MEMBER(nodemap_range2_rec, nrr_padding4);
+       CHECK_MEMBER(nodemap_range2_rec, nrr_netmask);
+}
+
 static void check_nodemap_id_rec(void)
 {
        BLANK_LINE();
diff --git a/lustre/utils/wiretest.c b/lustre/utils/wiretest.c
...

I will rebase this patch on the latest master to solve this.
